func solve(s string) int64 {
    n := len(s)
    if n == 0 {
        return 0
    }
    var base, L_count, LC_count int64
    for i := 0; i < n; i++ {
        switch s[i] {
        case 'L':
            L_count++
        case 'C':
            LC_count += L_count
        case 'T':
            base += LC_count
        }
    }

    prefix_L := make([]int64, n+1)
    prefix_L[0] = 0
    for i := 1; i <= n; i++ {
        prefix_L[i] = prefix_L[i-1]
        if i-1 < n && s[i-1] == 'L' {
            prefix_L[i]++
        }
    }

    suffix_T := make([]int64, n+1)
    suffix_T[n] = 0
    for i := n-1; i >= 0; i-- {
        suffix_T[i] = suffix_T[i+1]
        if s[i] == 'T' {
            suffix_T[i]++
        }
    }

    total_LC_prefix := make([]int64, n+1)
    var tempL, tempLC int64
    for i := 0; i < n; i++ {
        if s[i] == 'L' {
            tempL++
        } else if s[i] == 'C' {
            tempLC += tempL
        }
        total_LC_prefix[i+1] = tempLC
    }

    right_CT := make([]int64, n+1)
    var tempT int64
    right_CT[n] = 0
    for i := n-1; i >= 0; i-- {
        if s[i] == 'T' {
            tempT++
            right_CT[i] = right_CT[i+1]
        } else if s[i] == 'C' {
            right_CT[i] = right_CT[i+1] + tempT
        } else {
            right_CT[i] = right_CT[i+1]
        }
    }

    var max_additional int64
    for k := 0; k <= n; k++ {
        addL := right_CT[k]
        addC := prefix_L[k] * suffix_T[k]
        addT := total_LC_prefix[k]
        if addL > max_additional {
            max_additional = addL
        }
        if addC > max_additional {
            max_additional = addC
        }
        if addT > max_additional {
            max_additional = addT
        }
    }

    return base + max_additional
}
